import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(start, end):
        return np.linalg.norm(end - start) / truck_speed

    def is_within_time_window(visit_time, window):
        return window[0] <= visit_time <= window[1]

    n_customers = len(unvisited_customers)
    min_time_penalty = float('inf')
    best_node = None

    for i in range(n_customers):
        customer_pos = unvisited_customers[i]
        travel_to_customer = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_to_customer
        window_start, window_end = time_windows[i]

        if is_within_time_window(arrival_time, (window_start, window_end)):
            time_penalty = -window_end + arrival_time
        else:
            if arrival_time < window_start:
                time_penalty = window_start - arrival_time
            else:
                time_penalty = (arrival_time - window_end) * 10  # Large penalty for missing window

        if time_penalty < min_time_penalty:
            min_time_penalty = time_penalty
            best_node = i

        # Check if waiting is a better strategy
        if arrival_time < window_start:
            waiting_time_penalty = window_start - arrival_time
            if waiting_time_penalty < min_time_penalty:
                best_node = None  # Return None to wait

    return best_node
